import sys
from collections import deque

input_data = sys.stdin.buffer.read().split()
idx = 0

def rd():
    global idx
    v = input_data[idx]
    idx += 1
    return v

t = int(rd())

for _ in range(t):
    n, m = int(rd()), int(rd())
    grid = []
    lab_pos = None
    for i in range(n):
        row = rd().decode()
        grid.append(list(row))
        for j in range(m):
            if grid[i][j] == 'L':
                lab_pos = (i, j)

    dirs = [(-1,0),(1,0),(0,-1),(0,1)]

    # deg[i][j] = number of free neighbors (non-blocked)
    deg = [[0]*m for _ in range(n)]
    for i in range(n):
        for j in range(m):
            if grid[i][j] != '#':
                cnt = 0
                for di, dj in dirs:
                    ni, nj = i+di, j+dj
                    if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                        cnt += 1
                deg[i][j] = cnt

    good = [[False]*m for _ in range(n)]
    queue = deque()

    li, lj = lab_pos
    good[li][lj] = True
    queue.append((li, lj))

    while queue:
        ci, cj = queue.popleft()
        for di, dj in dirs:
            ni, nj = ci+di, cj+dj
            if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#' and not good[ni][nj]:
                deg[ni][nj] -= 1
                if deg[ni][nj] <= 1:
                    good[ni][nj] = True
                    queue.append((ni, nj))

    out = []
    for i in range(n):
        row = grid[i]
        for j in range(m):
            if row[j] == '.' and good[i][j]:
                row[j] = '+'
        out.append(''.join(row))

    print('\n'.join(out))
